/*
 * ldexp() test harness — prints (mantissa_hex, exponent, output_hex) triples.
 */

#include <math.h>
#include <stdint.h>
#include <stdio.h>
#include <float.h>

#ifdef EN_PERF
#define PF_COUNTER
#include "nds_pfcounter.h"
#endif

static inline uint64_t d2u(double d)
{
    union { double d; uint64_t u; } x;
    x.d = d;
    return x.u;
}

static inline double u2d(uint64_t u)
{
    union { double d; uint64_t u; } x;
    x.u = u;
    return x.d;
}

#ifdef EN_PERF
static volatile double g_acc;

static void emit(double x, int exp)
{
    volatile double vx = x;   /* prevent constant-folding of literal arguments */
    g_acc += ldexp(vx, exp);
}

static void emit_u(uint64_t bits, int exp)
{
    emit(u2d(bits), exp);
}
#else
static void emit(double x, int exp)
{
    double r = ldexp(x, exp);
    printf("%016llx %d %016llx\n", (unsigned long long)d2u(x), exp, (unsigned long long)d2u(r));
}

static void emit_u(uint64_t bits, int exp)
{
    emit(u2d(bits), exp);
}
#endif

static void test_representative_100(void)
{
    /* --- Section 1: Special IEEE 754 x values (8) --- */
    emit(0.0, 0);
    emit(-0.0, 0);
    emit(0.0, 10);                                    /* zero scaled by positive exp */
    emit_u(0x7ff8000000000000ULL, 0);  /* qNaN */
    emit_u(0x7ff0000000000001ULL, 0);  /* sNaN */
    emit_u(0xfff8000000000000ULL, 0);  /* -qNaN */
    emit_u(0x7ff0000000000000ULL, 5);  /* +Inf scaled */
    emit_u(0xfff0000000000000ULL, 5);  /* -Inf scaled */

    /* --- Section 2: Subnormal x values (8) --- */
    emit_u(0x0000000000000001ULL, 0);   /* min positive subnormal: 2^-1074, exp=0 */
    emit_u(0x8000000000000001ULL, 0);   /* min negative subnormal */
    emit_u(0x0008000000000000ULL, 0);   /* mid positive subnormal */
    emit_u(0x8008000000000000ULL, 0);   /* mid negative subnormal */
    emit_u(0x000fffffffffffffULL, 0);   /* max subnormal: just below DBL_MIN */
    emit_u(0x800fffffffffffffULL, 0);   /* max negative subnormal */
    emit_u(0x0000000000000001ULL, 1074); /* min subnormal scaled to 1.0 */
    emit_u(0x000fffffffffffffULL, 1);   /* max subnormal scaled up by 2 */

    /* --- Section 3: Normal boundary x values (8) --- */
    emit(DBL_MIN, 0);                                 /* 2^-1022, smallest normal */
    emit(-DBL_MIN, 0);
    emit_u(0x0010000000000001ULL, 0);  /* one ULP above DBL_MIN */
    emit(DBL_MAX, 0);                                 /* 0x7fefffffffffffff */
    emit(-DBL_MAX, 0);
    emit(DBL_MIN, 1);                                 /* DBL_MIN * 2 */
    emit(DBL_MIN, -1);                                /* DBL_MIN / 2 -> subnormal */
    emit_u(0x7fefffffffffffffULL, 0);  /* one ULP below DBL_MAX */

    /* --- Section 4: Near 1.0 x values (8) --- */
    emit_u(0x3fefffffffffffffULL, 0);  /* one ULP below 1.0 */
    emit(1.0, 0);
    emit_u(0x3ff0000000000001ULL, 0);  /* one ULP above 1.0 */
    emit(1.0, 1);                                     /* 1.0 * 2 = 2.0 */
    emit(1.0, -1);                                    /* 1.0 / 2 = 0.5 */
    emit(-1.0, 0);
    emit_u(0xbfefffffffffffffULL, 0);  /* one ULP toward zero from -1.0 */
    emit_u(0xbff0000000000001ULL, 0);  /* one ULP away from zero from -1.0 */

    /* --- Section 5: Powers-of-2 x with varied exp (10) --- */
    emit(1.0, 2);
    emit(1.0, 10);
    emit(1.0, -2);
    emit(1.0, -10);
    emit(0.5, 1);                                     /* 0.5 * 2 = 1.0 */
    emit(2.0, -1);                                    /* 2.0 / 2 = 1.0 */
    emit(4.0, -2);                                    /* 4.0 / 4 = 1.0 */
    emit(8.0, -3);                                    /* 8.0 / 8 = 1.0 */
    emit(1.0, 52);                                    /* 2^52: mantissa precision boundary */
    emit(1.0, -52);

    /* --- Section 6: Fractional mantissas with varied exp (8) --- */
    emit(0.5, 0);
    emit(1.5, 0);
    emit(1.5, 1);
    emit(1.5, -1);
    emit(1.25, 4);
    emit(1.75, -4);
    emit(0.75, 3);
    emit(-1.5, 5);

    /* --- Section 7: Boundary exponents - overflow/underflow thresholds (12) --- */
    emit(1.0, 1023);     /* near overflow: result = 2^1023 */
    emit(1.0, 1022);     /* 2^1022 */
    emit(1.0, 1024);     /* overflow: result = +Inf */
    emit(1.0, 2000);     /* far overflow */
    emit(1.0, -1022);    /* 2^-1022 = DBL_MIN */
    emit(1.0, -1023);    /* one below DBL_MIN -> subnormal */
    emit(1.0, -1074);    /* underflow threshold: 2^-1074 = min subnormal */
    emit(1.0, -1075);    /* underflow: 0 */
    emit(1.0, -2000);    /* far underflow */
    emit(-1.0, 1024);    /* overflow negative */
    emit(-1.0, -1075);   /* underflow negative */
    emit(1.5, 1023);     /* 1.5 * 2^1023 = overflow */

    /* --- Section 8: Negative x with varied exp (8) --- */
    emit(-0.5, 0);
    emit(-1.0, 1);
    emit(-2.0, -1);
    emit(-1.5, 10);
    emit(-1.5, -10);
    emit(-4.0, -2);
    emit(-1.0, -1022);   /* -> -DBL_MIN */
    emit(-1.0, 1023);    /* -> -2^1023 */

    /* --- Section 9: Large x with large/small exp (8) --- */
    emit(1.0e50, 0);
    emit(1.0e100, 0);
    emit(1.0e200, 0);
    emit(1.0e-200, 0);
    emit(1.0e50, -200);
    emit(1.0e-50, 200);
    emit(DBL_MAX / 2.0, 1);    /* half of DBL_MAX scaled up: result = DBL_MAX */
    emit(-DBL_MAX / 4.0, 2);   /* -DBL_MAX/4 * 4 = -DBL_MAX */

    /* --- Section 10: Mixed mantissa and exponent grid (22) --- */
    emit(0.5, 2);
    emit(0.5, -2);
    emit(0.75, 0);
    emit(0.75, 10);
    emit(1.25, 0);
    emit(1.25, -5);
    emit(1.5, 20);
    emit(1.5, -20);
    emit(1.75, 0);
    emit(1.75, 7);
    emit(2.0, 0);
    emit(2.0, 50);
    emit(2.0, -50);
    emit(-0.75, 5);
    emit(-1.25, 3);
    emit(-1.75, -3);
    emit(1.0e-10, 0);
    emit(-1.0e-10, 0);
    emit(1.0e10, 0);
    emit(-1.0e10, 0);
    emit(1.0, 100);
    emit(1.0, -100);
}

/* ------------------------------------------------------------------ */

/* 9. Random sweep: 300 (mantissa, exponent) pairs */
#ifndef EN_PERF
static void test_random_300(void)
{
    double mantissas[] = { 0.5, 0.75, 1.0, 1.25, 1.5, 1.75, 2.0, -0.5, -1.0, -1.5 };
    int nm = 10;
    int ne = 30;
    for (int i = 0; i < nm; i++) {
        for (int j = 0; j < ne; j++) {
            int exp = -14 + j;
            emit(mantissas[i], exp);
        }
    }
}
#endif

/* ------------------------------------------------------------------ */

int main(void)
{
#ifdef EN_PERF
    startPFM;
    test_representative_100();
    stopPFM;
    readResult();
    printf("perf: %016llx\n", (unsigned long long)d2u((double)g_acc));
#else
    test_representative_100();
    test_random_300();
#endif
    return 0;
}

